mapper.update:
UPDATE article
SET title = #{title}, content = #{content}, summary = #{summary}, category_id = #{categoryId}, update_time = #{updateTime}
WHERE id = #{id}

mapper.select:
SELECT a.id, a.user_id, a.category_id, a.title, a.content, a.summary, a.view_count, a.like_count, a.create_time, a.update_time, u.nickname AS author_nickname, u.avatar AS author_avatar FROM article a LEFT JOIN `user` u ON a.user_id = u.id
(a.title LIKE CONCAT('%', #{keyword}, '%') OR a.content LIKE CONCAT('%', #{keyword}, '%'))
AND
a.category_id = #{categoryId}
ORDER BY a.create_time DESC
LIMIT #{pageSize} OFFSET #{offset}
